import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function SupervisorDashboard() {
  const [locations, setLocations] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);

  const [priority, setPriority] = useState("Medium");
  const [showDropdown, setShowDropdown] = useState(false);

  const [allRequests, setAllRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);

  const supervisorId = localStorage.getItem("id");

  useEffect(() => {
    getLocations();
    getAllRequests();
    getMyRequests();
  }, []);

  // ================= LOCATIONS =================
  const getLocations = async () => {
    try {
      const res = await axios.get(Api.get_All_Locations);
      setLocations(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // ================= ALL REQUESTS =================
  const getAllRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      const data = res.data?.data || res.data || [];
      setAllRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setAllRequests([]);
    }
  };

  // ================= MY REQUESTS =================
  const getMyRequests = async () => {
    try {
      const res = await axios.get(
        `${Api.get_My_Emg_Req}/${supervisorId}`
      );
     console.log(res.data);
      const data = res.data?.data || res.data || [];
      setMyRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setMyRequests([]);
    }
  };

  // ================= CREATE REQUEST =================
const handleSubmit = async () => {
  try {
    if (!selectedLocation) {
      return alert("Please select location");
    }

    const res = await axios.post(Api.create_Emg_Req, {
      requestedBy: supervisorId,
      location: selectedLocation._id,
      priority,
    });

    alert(res.data.message || "Request Created Successfully");

    getAllRequests();
    getMyRequests();

    // reset UI
    setSelectedLocation(null);
    setSearch("");
    setPriority("Medium");
    setShowDropdown(false);

  } catch (err) {
    console.log(err);

    alert(
      err.response?.data?.message ||
      "This location already has an active request"
    );
  }
};

  const steps = ["Pending", "Accepted", "Scheduled", "Arrived", "Completed"];

  return (

  <div className="min-h-screen bg-[#eef2ea] flex justify-center py-6">
  <div className="w-full max-w-md bg-[#f4f6f0] rounded-[35px] border-[10px] border-gray-400 overflow-hidden shadow-xl">

    {/* HEADER */}
    <div className="px-6 py-5 border-b">
      <h1 className="text-2xl font-bold text-green-900 flex items-center gap-2">
        🚛 GarbagePickupVehicle
      </h1>
    </div>

    <div className="p-5">

      {/* TITLE */}
      <p className="uppercase text-xs tracking-widest text-gray-600 font-semibold">
        Fleet Management
      </p>

      <h2 className="text-4xl font-bold text-green-900 mt-2 mb-6">
        Create Pickup Request
      </h2>

      {/* LOCATION CARD */}
      <div className="bg-white rounded-2xl border p-5 mb-5 shadow-sm">
        <div className="flex justify-between items-center mb-4">
          <h3 className="font-bold text-xl">
            📍 Location
          </h3>

          <button className="text-green-900 font-semibold text-sm">
            ⊙ Use Current
          </button>
        </div>

        <div className="relative">
          <input
            placeholder="Search pickup address..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setShowDropdown(true);
            }}
            className="w-full border rounded-xl p-3 pr-10 text-lg"
          />

          <span className="absolute right-4 top-3 text-xl">
            🔍
          </span>
        </div>

        {showDropdown && (
          <div className="mt-2 bg-white border rounded-xl max-h-40 overflow-y-auto">
            {locations
              .filter((l) =>
                l.location
                  .toLowerCase()
                  .includes(search.toLowerCase())
              )
              .map((loc) => (
                <div
                  key={loc._id}
                  onClick={() => {
                    setSelectedLocation(loc);
                    setSearch(loc.location);
                    setShowDropdown(false);
                  }}
                  className="p-3 hover:bg-gray-100 cursor-pointer"
                >
                  {loc.location}
                </div>
              ))}
          </div>
        )}
      </div>

      {/* PRIORITY */}
      <div className="bg-white rounded-2xl border p-5 mb-6 shadow-sm">
        <h3 className="font-bold text-2xl mb-4">
          🎯 Priority Level
        </h3>

        <div className="flex gap-2">
          {["Low", "Medium", "High"].map((p) => (
            <button
              key={p}
              onClick={() => setPriority(p)}
              className={`flex-1 py-3 rounded-full text-lg font-semibold transition
                ${
                  priority === p
                    ? "bg-green-900 text-white"
                    : "bg-white border"
                }`}
            >
              {p}
            </button>
          ))}
        </div>
      </div>

      {/* SUBMIT BUTTON */}
      <button
        onClick={handleSubmit}
        className="w-full bg-green-900 text-white py-4 rounded-2xl text-2xl font-bold shadow-lg"
      >
        ➤ Submit & Notify Driver
      </button>

      <p className="text-center text-xs text-gray-600 mt-3">
        Notifications will be sent to the dispatcher and
        the assigned unit.
      </p>

      {/* REQUEST STATUS */}
      <div className="mt-10">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-3xl font-bold leading-tight">
            Active Request <br />
            Status
          </h3>

          <span className="italic text-gray-500 text-sm">
            Completed moved to History
          </span>
        </div>

        {allRequests.map((req) => (
          <div
            key={req._id}
            className="bg-white border rounded-2xl mb-4 overflow-hidden shadow-sm"
          >
            <div className="p-4 flex justify-between items-center">
              <div>
                <p className="text-xs text-gray-500 uppercase">
                  Request #{req._id.slice(-4)}
                </p>

                <p className="text-green-800 text-xl font-medium">
                  {req.location?.location}
                </p>
              </div>

              <span
                className={`px-4 py-1 rounded-full text-sm font-bold text-white
                ${
                  req.status === "Completed"
                    ? "bg-green-700"
                    : req.status === "Accepted"
                    ? "bg-green-600"
                    : "bg-gray-400"
                }`}
              >
                {req.status?.toUpperCase()}
              </span>
            </div>

            {/* Timeline */}
            <div className="border-t px-5 py-4">
              <div className="flex items-start gap-3">
                <div className="w-8 h-8 bg-green-900 rounded-full flex items-center justify-center text-white">
                  ✓
                </div>

                <div>
                  <p className="font-semibold">
                    {req.status}
                  </p>

                  <p className="text-sm text-gray-500">
                    {new Date(
                      req.createdAt
                    ).toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </p>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* BOTTOM NAV */}
      <div className="mt-8 border-t pt-4 flex justify-around">
        <div className="bg-green-800 text-white px-5 py-2 rounded-full">
          🏠 Home
        </div>

        <div>🕘 History</div>

        <div>👤 Profile</div>
      </div>

    </div>
  </div>
</div>
  );
}
